-- ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft') تحت "المعاملات"
-- (muamalat) — 21 تصنيفاً فرعياً (العنقود الأكبر التالي بعد استنفاد
-- aqeedah-tawheed بالكامل في دفعات سابقة). كل تصنيف يحصل على درس واحد
-- حقيقي (lessons + lesson_sections + lesson_citations)، مبني على مصادر
-- فقهية معتمدة (الفقه الإسلامي وأدلته للزحيلي، الملخص الفقهي للفوزان،
-- المغني لابن قدامة، الفقه الميسر لوزارة الأوقاف الكويتية، المعاملات
-- المالية المعاصرة لشبير) وقرارات مجمع الفقه الإسلامي الدولي المتحقَّقة
-- مباشرة عبر WebFetch من iifa-aifi.org (التأمين: قرار 9(9/2) جدة 1985؛
-- الحقوق الفكرية: قرار 43(5/5) الكويت 1988؛ العقود بوسائل الاتصال
-- الحديثة: قرار 54(3/6)؛ العملات الرقمية: قرار 237(24/8) دبي 2019،
-- متحقَّق سابقاً). كل آية مُستشهَد بها تحقَّقت حرفياً من
-- public/data/quran محلياً قبل الإدراج. كل حديث مستشهَد به من الأحاديث
-- المتفق عليها أو المشهورة الثابتة التخريج (لا حديث ذو تصحيح متذبذب).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الـ21 عند اكتمال محتواها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) البيوع
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='3b552439-cb03-44de-8bc7-1ec7a68b8d53' AND title='أحكام البيوع وأركانها في الفقه الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام البيوع وأركانها في الفقه الإسلامي', 'تعريف البيع وأركانه وشروط صحته وأثر التراضي في حِلّه', '3b552439-cb03-44de-8bc7-1ec7a68b8d53', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريف البيع وأركانه', 'البيع في اصطلاح الفقهاء مبادلة مال بمال على وجه مخصوص يفيد التمليك، وله ثلاثة أركان: العاقدان (البائع والمشتري)، والصيغة (الإيجاب والقبول)، والمعقود عليه (المبيع والثمن). ويشترط لصحته أن يكون العاقدان أهلاً للتصرف، وأن يتراضيا، وأن يكون المبيع معلوماً مقدوراً على تسليمه ومباحاً الانتفاع به شرعاً، فإن اختل شرط من هذه الشروط بطل العقد أو فسد بحسب نوع الخلل.', 1),
    (v_lesson, 'evidence', 'الأصل في حل البيع', 'الأصل في البيع الحل، قال تعالى: ﴿وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا﴾ (البقرة: 275)، وجعل سبحانه التراضي شرطاً لحل انتقال الأموال بين الناس بالمعاوضة، فقال: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ﴾ (النساء: 29).', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'كتاب البيوع من «الفقه الإسلامي وأدلته» — د. وهبة الزحيلي', 1);
  END IF;

  -- 2) الربا
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='3d177331-9a8d-4547-89dc-461caee2dffc' AND title='تحريم الربا وأنواعه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تحريم الربا وأنواعه', 'بيان حرمة الربا في الإسلام، وأنواعه (الفضل والنسيئة)، وتدرج تحريمه في القرآن', '3d177331-9a8d-4547-89dc-461caee2dffc', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أنواع الربا', 'الربا نوعان: ربا الفضل، وهو الزيادة في أحد العوضين عند مبادلة مالين من جنس واحد من الأموال الربوية (كبيع صاع تمر بصاعين منه)، وربا النسيئة، وهو الزيادة المشروطة على الدَّين مقابل تأجيل سداده، وهو ربا الجاهلية الذي كان شائعاً قبل الإسلام. وقد ثبت تحريم ربا الفضل في الأصناف الستة (الذهب والفضة والبر والشعير والتمر والملح) في حديث عبادة بن الصامت رضي الله عنه عند مسلم، وقاس عليها جمهور الفقهاء ما شابهها من الأموال الربوية.', 1),
    (v_lesson, 'evidence', 'تدرج التحريم في القرآن', 'جاء تحريم الربا في القرآن على مراحل ختمت بالتحريم القاطع والوعيد الشديد، قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَذَرُوا مَا بَقِيَ مِنَ الرِّبَا إِنْ كُنْتُمْ مُؤْمِنِينَ فَإِنْ لَمْ تَفْعَلُوا فَأْذَنُوا بِحَرْبٍ مِنَ اللَّهِ وَرَسُولِهِ﴾ (البقرة: 278-279)، وهذا من أشد آيات الوعيد في القرآن كله، مما يدل على عظم خطر الربا على الفرد والمجتمع.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'باب الربا من «الملخص الفقهي» — الشيخ صالح بن فوزان الفوزان', 1);
  END IF;

  -- 3) عقود التوثيق والإرفاق
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='887b9859-1c27-4d52-bb14-defccefa4508' AND title='عقود التوثيق والإرفاق وتصنيفها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('عقود التوثيق والإرفاق وتصنيفها', 'تعريف عقود التوثيق التي تضمن الحقوق وعقود الإرفاق القائمة على الإحسان بين الناس', '887b9859-1c27-4d52-bb14-defccefa4508', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تصنيف العقود المالية', 'يقسم الفقهاء العقود المالية باعتبار المقصود منها إلى ثلاثة أقسام: عقود معاوضات يُقصَد بها الربح كالبيع والإجارة، وعقود تبرعات يُقصَد بها الإحسان المحض كالهبة والوقف، وعقود توثيق وإرفاق يُقصَد بها ضمان الحقوق وتيسير التعامل بين الناس من غير قصد الربح، كالرهن والكفالة والحوالة توثيقاً للدَّين، والوديعة والعارية والقرض إرفاقاً وتيسيراً على المحتاج. وهذا التصنيف أصل مهم تُبنى عليه دراسة سائر أبواب المعاملات المالية.', 1),
    (v_lesson, 'evidence', 'الأمر بتوثيق الحقوق', 'أمر الله عز وجل بتوثيق الديون كتابة وإشهاداً حفظاً لها من الضياع والنزاع، فقال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا تَدَايَنْتُمْ بِدَيْنٍ إِلَىٰ أَجَلٍ مُسَمًّى فَاكْتُبُوهُ﴾ (البقرة: 282)، وفي هذا تأصيل قرآني لمشروعية عقود التوثيق كافة وحفظ لحقوق الناس بينهم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', '«بداية المجتهد ونهاية المقتصد» — ابن رشد الحفيد (في تصنيف عقود المعاملات)', 1);
  END IF;

  -- 4) الوقف والهبة والوصية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8e1eff9b-c810-4af6-b8bb-b535380793c8' AND title='أحكام الوقف والهبة والوصية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام الوقف والهبة والوصية', 'تعريف عقود التبرع الثلاثة، وحكم كل منها، ومقدار جواز الوصية', '8e1eff9b-c810-4af6-b8bb-b535380793c8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الوقف حبس الأصل وتسبيل المنفعة، بأن يمنع صاحب المال من التصرف في عين ماله ويجعل منفعتها في وجه من وجوه الخير بصفة مؤبدة، وأصله حديث عمر رضي الله عنه في أرضه بخيبر عند البخاري ومسلم إذ قال له النبي ﷺ: «إن شئت حبَّست أصلها وتصدقت بها». والهبة تمليك مال لآخر حال الحياة بلا عوض. والوصية عهد يوصي فيه الشخص بشيء من ماله لينفَّذ بعد موته، ولا تجوز بأكثر من الثلث لغير وارث.', 1),
    (v_lesson, 'evidence', 'حديث سعد في نصاب الوصية', 'حدَّد النبي ﷺ نصاب الوصية في حديث سعد بن أبي وقاص رضي الله عنه المتفق عليه، إذ لما استأذنه أن يوصي بماله كله قال: «لا»، قال: فبالشطر؟ قال: «لا»، قال: فبالثلث؟ قال: «الثلث، والثلث كثير، إنك أن تذر ورثتك أغنياء خير من أن تذرهم عالة يتكففون الناس».', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'باب الوقف والهبة والوصية من «الفقه الميسر» — لجنة علمية، وزارة الأوقاف الكويتية', 1);
  END IF;

  -- 5) المعاملات البنكية المعاصرة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d0be8c64-190a-44cc-b969-dc3b0383c0f4' AND title='ضوابط التعامل مع البنوك المعاصرة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('ضوابط التعامل مع البنوك المعاصرة', 'التمييز بين المعاملات البنكية الجائزة والمحرمة، وأبرز صيغ التمويل الإسلامي البديلة', 'd0be8c64-190a-44cc-b969-dc3b0383c0f4', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'أنواع المعاملات البنكية', 'تتفاوت المعاملات البنكية المعاصرة بين الجائز والمحرم. فالحساب الجاري بلا فوائد يأخذ حكم القرض الذي يضمنه البنك، وهو جائز. أما الودائع الاستثمارية ذات الفائدة الثابتة المسبقة فهي من الربا المحرم لأنها زيادة مشروطة على أصل الدَّين. وقد طوَّرت البنوك الإسلامية بدائل شرعية كالمرابحة للآمر بالشراء، والمضاربة، والمشاركة، والإجارة المنتهية بالتمليك، تقوم على البيع الحقيقي أو المشاركة في الربح والخسارة بدل الإقراض بفائدة.', 1),
    (v_lesson, 'evidence', 'الضابط الشرعي العام', 'الأصل الذي تُبنى عليه هذه البدائل هو حل البيع وحرمة الربا: ﴿وَأَحَلَّ اللَّهُ الْبَيْعَ وَحَرَّمَ الرِّبَا﴾ (البقرة: 275)، فكل صيغة تمويل بنكي يُنظر فيها: إن كانت مبنية على بيع حقيقي أو مشاركة في ربح وخسارة فهي جائزة، وإن كانت قرضاً بزيادة مشروطة فهي من الربا المحرم مهما تغيّر اسمها أو شكلها القانوني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', '«المعاملات المالية المعاصرة» — د. محمد عثمان شبير', 1);
  END IF;

  -- 6) الأسهم والصكوك
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='65b82610-e1da-4c06-aab0-6d89703a5003' AND title='حكم التعامل بالأسهم والصكوك') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم التعامل بالأسهم والصكوك', 'ضوابط جواز الاستثمار في الأسهم والفرق الشرعي بين السهم والصك والسند', '65b82610-e1da-4c06-aab0-6d89703a5003', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها والفرق بينها', 'السهم حصة شائعة في رأس مال شركة مساهمة تمثل ملكية جزء من موجوداتها، ويجوز تداوله إذا كان نشاط الشركة مباحاً خالياً من المحرمات كالربا والقمار. أما الصك فأداة استثمارية تمثل حصة شائعة في ملكية أعيان أو منافع أو مشروع معين، تُبنى على عقود شرعية كالمضاربة والإجارة والمشاركة، بخلاف السند الربوي الذي هو مجرد دين بفائدة محرمة لا ملكية حقيقية فيه.', 1),
    (v_lesson, 'evidence', 'ضابط جواز المساهمة', 'أصل جواز اقتناء حصة من أصول الشركة هو عموم مشروعية البيع والشركة، فالمساهم شريك حقيقي في مال الشركة ونشاطها ما دام مباحاً، عملاً بقوله تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا أَوْفُوا بِالْعُقُودِ﴾ (المائدة: 1). وقد وضعت هيئة المحاسبة والمراجعة للمؤسسات المالية الإسلامية (أيوفي) في معيارها الشرعي رقم (21) ضوابط تفصيلية لفرز الأسهم المباحة عن غيرها من حيث نشاط الشركة ونسب مديونيتها وإيراداتها المحرمة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المعيار الشرعي رقم (21) «الأسهم» — هيئة المحاسبة والمراجعة للمؤسسات المالية الإسلامية (أيوفي)', 1);
  END IF;

  -- 7) العملات الرقمية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='4d7f1bfd-f545-476b-b124-b956a94f3a2a' AND title='العملات الرقمية المشفَّرة بين الفقهاء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('العملات الرقمية المشفَّرة بين الفقهاء', 'عرض موضوعي للجدل الفقهي المعاصر حول طبيعة العملات الرقمية وحكمها', '4d7f1bfd-f545-476b-b124-b956a94f3a2a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التكييف الفقهي المختلف فيه', 'العملات الرقمية المشفَّرة (كالبيتكوين) أصول رقمية لا مركزية تُتداول عبر تقنية سلاسل الكتل (blockchain) دون إصدار أو ضمان من جهة سيادية. اختلف الفقهاء المعاصرون في تكييفها: فمنهم من يراها سلعة أو مالاً منفعته معتبرة عرفاً يجوز التعامل بها بضوابط، ومنهم من يمنعها لعدم استقرار قيمتها الشديد وشيوع الغرر والجهالة فيها، ومنهم من يتوقف حتى تتضح طبيعتها الاقتصادية والقانونية أكثر.', 1),
    (v_lesson, 'evidence', 'قرار مجمع الفقه الإسلامي الدولي', 'درس مجمع الفقه الإسلامي الدولي (التابع لمنظمة التعاون الإسلامي) مسألة العملات الرقمية المشفَّرة في دورته الرابعة والعشرين بدبي (نوفمبر 2019)، وقرر في القرار رقم 237 (24/8) تأجيل البتّ فيها لعدم استقرار طبيعتها القانونية والاقتصادية وعدم حسم كونها سلعة أو خدمة أو أصلاً استثمارياً، وأوصى بمزيد من الدراسة قبل إصدار حكم قاطع.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 237 (24/8) بشأن العملات الرقمية المشفَّرة — دورة دبي 2019', 1);
  END IF;

  -- 8) التأمين
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='86a63daf-0b71-4772-bc02-8eb7cebfb4b8' AND title='التأمين التجاري والتعاوني') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('التأمين التجاري والتعاوني', 'التمييز الفقهي بين التأمين التجاري المحرم والتأمين التعاوني الجائز', '86a63daf-0b71-4772-bc02-8eb7cebfb4b8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الفرق بين النوعين', 'التأمين التجاري عقد معاوضة يلتزم فيه أحد الطرفين بدفع مبلغ مالي عند وقوع خطر محدد مقابل قسط يدفعه المؤمَّن له، وقد أفتت المجامع الفقهية المعاصرة بتحريمه لاشتماله على الغرر الفاحش والقمار وأحياناً الربا في استثمار الأقساط. أما التأمين التعاوني فنظام يتعاون فيه المشتركون على تحمل الأخطار فيما بينهم بالتبرع، وتُدار أموالهم بلا قصد ربح لشركة الإدارة مقابل أجر معلوم، فأجازه الفقهاء لقيامه على التبرع لا المعاوضة المحضة.', 1),
    (v_lesson, 'evidence', 'قرار مجمع الفقه الإسلامي الدولي', 'قرر مجمع الفقه الإسلامي الدولي في دورته الثانية بجدة (1985) في القرار رقم 9 (9/2) أن التأمين التجاري ذا القسط الثابت يشتمل على «غرر كبير مفسد للعقد» فهو محرم، واقترح التأمين التعاوني بديلاً شرعياً «قائماً على أساس التبرع والتعاون»، ودعا الدول الإسلامية إلى إنشاء مؤسسات تأمين تعاوني.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 9 (9/2) بشأن التأمين وإعادة التأمين — دورة جدة 1985', 1);
  END IF;

  -- 9) التجارة الإلكترونية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c48bf513-5830-441d-9688-69ece21d2a40' AND title='أحكام التعاقد في التجارة الإلكترونية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام التعاقد في التجارة الإلكترونية', 'انطباق ضوابط البيع الشرعية على التعاقد عبر وسائل الاتصال الحديثة والإنترنت', 'c48bf513-5830-441d-9688-69ece21d2a40', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'طبيعة مجلس العقد الإلكتروني', 'التجارة الإلكترونية تعاقد يتم بين طرفين غير متواجدين في مكان واحد عبر وسيلة اتصال حديثة (كالإنترنت)، وقد قرر الفقهاء المعاصرون أن هذا النوع من التعاقد يأخذ حكم التعاقد بين الحاضرين إذا اتحد وقت صدور الإيجاب والقبول، فتنطبق عليه أحكام البيع العامة من حيث معلومية المبيع والثمن والقدرة على التسليم وخلوّه من الغرر والربا، مع اعتبار وسيلة الدفع والتوثيق الإلكتروني قائمة مقام الكتابة والإشهاد المعتادين.', 1),
    (v_lesson, 'evidence', 'قرار التعاقد بوسائل الاتصال الحديثة', 'أصَّل مجمع الفقه الإسلامي الدولي لهذه المسألة في دورته السادسة (شعبان 1410هـ) بالقرار رقم 54 (3/6)، وقرر أن التعاقد بين طرفين في مكانين مختلفين عبر وسيلة اتصال فورية كالهاتف يُعَدّ تعاقداً بين حاضرين تنطبق عليه أحكام مجلس العقد المعتادة، وأن الإيجاب المحدد بمدة يلزم صاحبه المحافظة عليه خلالها. وهذا القرار هو الأصل الذي بُنيت عليه أحكام التعاقد الإلكتروني لاحقاً.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 54 (3/6) بشأن إجراء العقود بآلات الاتصال الحديثة — الدورة السادسة، 1410هـ', 1);
  END IF;

  -- 10) الحقوق الفكرية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1e45bcb4-0674-4ac4-81fc-61eef31f00ca' AND title='حكم الحقوق الفكرية في الفقه الإسلامي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم الحقوق الفكرية في الفقه الإسلامي', 'اعتبار الفقه المعاصر للاسم التجاري والعلامة التجارية وحق التأليف والاختراع حقوقاً خاصة مصونة', '1e45bcb4-0674-4ac4-81fc-61eef31f00ca', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الحقوق الفكرية وقيمتها', 'الحقوق الفكرية أو المعنوية هي حقوق غير مادية تنشأ عن الإبداع الذهني، كحق التأليف وحق الاختراع والابتكار والاسم التجاري والعلامة التجارية والعنوان التجاري. وقد اكتسبت هذه الحقوق في العصر الحديث قيمة مالية معتبرة، فبحث الفقهاء المعاصرون حكمها لعدم ورود نص خاص فيها عند المتقدمين، وانتهوا إلى اعتبارها حقوقاً خاصة لأصحابها معترفاً بها شرعاً لا يجوز الاعتداء عليها.', 1),
    (v_lesson, 'evidence', 'قرار مجمع الفقه الإسلامي الدولي', 'قرر مجمع الفقه الإسلامي الدولي في دورته الخامسة بالكويت (ديسمبر 1988) بالقرار رقم 43 (5/5) أن «الاسم التجاري، والعنوان التجاري، والعلامة التجارية، والتأليف، والاختراع أو الابتكار، هي حقوق خاصة» لأصحابها، معترف بها شرعاً، ولا يجوز الاعتداء عليها، ويجوز التصرف فيها بعوض مالي متى انتفى عنها الغرر والتدليس.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'قرار مجمع الفقه الإسلامي الدولي رقم 43 (5/5) بشأن الحقوق المعنوية — دورة الكويت 1988', 1);
  END IF;

  -- 11) الوكالة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2d389df3-ed0a-4799-9b27-16b778da9e3c' AND title='عقد الوكالة وأحكامه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('عقد الوكالة وأحكامه', 'تعريف الوكالة وأركانها ودليل مشروعيتها من القرآن', '2d389df3-ed0a-4799-9b27-16b778da9e3c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأركانها', 'الوكالة عقد استنابة يقيم فيه شخص (الموكِّل) آخر (الوكيل) مقامه في تصرف جائز معلوم، فيقوم الوكيل بالتصرف نيابة عن الموكِّل ويعود أثره إليه. وتكون في البيع والشراء والزواج والخصومة وسائر التصرفات المالية وغيرها، وتنعقد بالإيجاب والقبول صريحاً أو دلالة، وتنتهي بموت أحد الطرفين أو عزل الوكيل أو تنفيذ العمل الموكَّل فيه.', 1),
    (v_lesson, 'evidence', 'دليل مشروعيتها', 'من أدلة مشروعية الوكالة قصة أصحاب الكهف في القرآن، إذ استناب بعضهم بعضاً في شراء الطعام، قال تعالى: ﴿فَابْعَثُوا أَحَدَكُمْ بِوَرِقِكُمْ هَٰذِهِ إِلَى الْمَدِينَةِ فَلْيَنْظُرْ أَيُّهَا أَزْكَىٰ طَعَامًا فَلْيَأْتِكُمْ بِرِزْقٍ مِنْهُ﴾ (الكهف: 19)، وهي استنابة في الشراء وهو عين الوكالة، وقد استناب النبي ﷺ أصحابه في مهام مالية وسفارات عدة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'باب الوكالة من «الفقه الإسلامي وأدلته» — د. وهبة الزحيلي', 1);
  END IF;

  -- 12) الحجر
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5a432441-ace7-4d5d-a01a-119ecdb3bb71' AND title='الحجر: أنواعه وأحكامه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الحجر: أنواعه وأحكامه', 'تعريف الحجر وأسبابه وحكمة منع التصرف عن بعض الناس صيانة لأموالهم', '5a432441-ace7-4d5d-a01a-119ecdb3bb71', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وأسبابه', 'الحجر في اصطلاح الفقهاء منع شخص معين من التصرف في ماله لعارض يقتضي هذا المنع، إما لمصلحته كالصغر والجنون والسفه، وإما لمصلحة غيره كحجر المفلس لحق غرمائه. فالصغير والمجنون يُحجَر عليهما حتى يبلغا رشدهما، والسفيه (من لا يحسن التصرف في ماله فيبذره في غير موضعه) يُحجَر عليه وإن كان بالغاً عاقلاً صيانة لماله من الضياع.', 1),
    (v_lesson, 'evidence', 'دليله من القرآن', 'قال تعالى: ﴿وَلَا تُؤْتُوا السُّفَهَاءَ أَمْوَالَكُمُ الَّتِي جَعَلَ اللَّهُ لَكُمْ قِيَامًا وَارْزُقُوهُمْ فِيهَا وَاكْسُوهُمْ وَقُولُوا لَهُمْ قَوْلًا مَعْرُوفًا﴾ (النساء: 5)، ففي الآية دليل صريح على منع السفيه من التصرف المباشر في ماله صيانة له من التبذير، مع وجوب الإنفاق عليه من هذا المال بالمعروف.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'كتاب الحجر من «المغني» — ابن قدامة المقدسي', 1);
  END IF;

  -- 13) الضمان والكفالة والحوالة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5848323f-bddc-4009-b812-bcabe1d965d4' AND title='الضمان والكفالة والحوالة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الضمان والكفالة والحوالة', 'تعريف عقود التوثيق الثلاثة القائمة على ضم ذمة أو نقل دين، وأدلة مشروعيتها', '5848323f-bddc-4009-b812-bcabe1d965d4', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الكفالة (أو الضمان) ضم ذمة الكفيل إلى ذمة المكفول عنه في المطالبة بحق، فيصير الكفيل ملتزماً بأداء الحق إن لم يؤده الأصيل. والحوالة نقل الدَّين من ذمة المحيل (المدين الأصلي) إلى ذمة المحال عليه، فتبرأ ذمة المحيل ويصبح المحال عليه هو المطالَب بالدَّين. وكلاهما من عقود التوثيق التي تحفظ حقوق الدائنين وتيسر التعامل بين الناس.', 1),
    (v_lesson, 'evidence', 'دليلها من السنة', 'من أدلة مشروعية الكفالة حديث أبي أمامة رضي الله عنه عند الترمذي وحسَّنه، أن النبي ﷺ قال: «الزعيم غارم»، أي الكفيل ضامن لما كفل به. ومن أدلة مشروعية الحوالة حديث أبي هريرة رضي الله عنه المتفق عليه: «مطل الغني ظلم، وإذا أُتبع أحدكم على مليء فليتبع»، ومعناه إذا أحيل الدائن على مدين موسر وجب عليه قبول الحوالة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'باب الضمان والكفالة والحوالة من «الفقه الميسر» — لجنة علمية، وزارة الأوقاف الكويتية', 1);
  END IF;

  -- 14) الصلح والشفعة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8cbbe640-2868-4325-b1a7-deaeef2638a1' AND title='الصلح والشفعة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الصلح والشفعة', 'تعريف الصلح وفضله، وتعريف الشفعة وشروط ثبوتها بين الشركاء', '8cbbe640-2868-4325-b1a7-deaeef2638a1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الصلح عقد يُرفَع به نزاع بين متخاصمين برضاهما، إما بإسقاط جزء من الحق أو باستبدال حق بآخر. والشفعة حق تملُّك الشريك حصة شريكه المبيعة لأجنبي بمثل ثمنها، دفعاً لضرر الشراكة الجديدة مع الغريب، وتثبت في العقار غير المقسوم غالباً عند جمهور الفقهاء، وتسقط إن لم يطالب بها الشفيع فور علمه بالبيع.', 1),
    (v_lesson, 'evidence', 'أدلتها', 'أثنى القرآن على الصلح بقوله تعالى: ﴿وَالصُّلْحُ خَيْرٌ﴾ (النساء: 128). وثبتت مشروعية الشفعة بحديث جابر بن عبدالله رضي الله عنهما عند البخاري: «قضى النبي ﷺ بالشفعة في كل ما لم يُقسم، فإذا وقعت الحدود وصُرِّفت الطرق فلا شفعة».', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'كتابا الصلح والشفعة من «المغني» — ابن قدامة المقدسي', 1);
  END IF;

  -- 15) الغصب واللقطة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b26fce99-50c6-4f60-9808-256791a229c9' AND title='الغصب واللقطة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الغصب واللقطة', 'تحريم أخذ مال الغير بغير حق، وأحكام التعامل مع المال الضائع الملتقَط', 'b26fce99-50c6-4f60-9808-256791a229c9', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'الغصب الاستيلاء على مال الغير قهراً بغير حق، وهو من كبائر الذنوب المحرمة إجماعاً، ويجب على الغاصب رد العين المغصوبة إن بقيت أو ضمان قيمتها إن تلفت. واللقطة مال ضائع يجده شخص فيلتقطه، ويجب عليه تعريفه (الإعلان عنه) مدة معينة، فإن جاء صاحبه ردَّه إليه، وإلا جاز له تملكه أو التصدق به بحسب تفصيل الفقهاء.', 1),
    (v_lesson, 'evidence', 'أدلتهما', 'ثبت تحريم الغصب بحديث سعيد بن زيد رضي الله عنه المتفق عليه: «من اقتطع شبراً من الأرض ظلماً طوَّقه إلى سبع أرضين». وثبت حكم اللقطة بحديث زيد بن خالد الجهني رضي الله عنه المتفق عليه، إذ سأل النبي ﷺ عن اللقطة فقال: «اعرف عفاصها ووكاءها، ثم عرِّفها سنة، فإن جاء صاحبها فادفعها إليه، وإلا فشأنك بها».', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'كتابا الغصب واللقطة من «الفقه الإسلامي وأدلته» — د. وهبة الزحيلي', 1);
  END IF;

  -- 16) الوديعة والعارية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='67832ab4-ebb8-4213-ad4b-814d8a9ec518' AND title='الوديعة والعارية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الوديعة والعارية', 'تعريف عقدي الأمانة القائمين على حفظ المال أو إعارة الانتفاع به مجاناً', '67832ab4-ebb8-4213-ad4b-814d8a9ec518', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'الوديعة توكيل شخص آخر بحفظ ماله عنده تبرعاً، فيد المودَع عنده يد أمانة لا يضمن ما تلف عنده إلا بتعدٍّ أو تقصير. والعارية تمليك منفعة عين مباحة مدة معينة بلا عوض، كإعارة كتاب أو أداة، وهي من عقود الإرفاق والإحسان بين الناس التي حث عليها الإسلام.', 1),
    (v_lesson, 'evidence', 'أدلتهما', 'دلَّ على وجوب أداء الوديعة قوله تعالى: ﴿إِنَّ اللَّهَ يَأْمُرُكُمْ أَنْ تُؤَدُّوا الْأَمَانَاتِ إِلَىٰ أَهْلِهَا﴾ (النساء: 58). وذمَّ الله تعالى مانعي العارية بقوله: ﴿وَيَمْنَعُونَ الْمَاعُونَ﴾ (الماعون: 7)، وقد فسَّر جمع من المفسرين "الماعون" بما يتعاوره الناس بينهم من الأدوات كالدلو والفأس، فكان منع إعارتها مذموماً شرعاً.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'بابا الوديعة والعارية من «الملخص الفقهي» — الشيخ صالح بن فوزان الفوزان', 1);
  END IF;

  -- 17) الشركة والمضاربة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='bf2353f9-e592-494d-be59-aca88ec83906' AND title='الشركة والمضاربة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الشركة والمضاربة', 'تعريف عقد الشركة بأنواعه وعقد المضاربة القائم على المال والعمل', 'bf2353f9-e592-494d-be59-aca88ec83906', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'الشركة عقد بين اثنين فأكثر على الاشتراك في رأس مال ليعملا فيه، ويكون الربح والخسارة بينهما بحسب الاتفاق، ولها أنواع عند الفقهاء كشركة العنان وشركة الأبدان. والمضاربة نوع خاص منها، هي عقد بين صاحب مال (رب المال) وعامل يتَّجر فيه، فإن ربح كان الربح بينهما بحسب النسبة المتفق عليها، وإن خسر المال بلا تعدٍّ من العامل فالخسارة على رب المال وحده وخسر العامل جهده.', 1),
    (v_lesson, 'evidence', 'أدلتهما', 'دلَّ القرآن على مشروعية الاشتراك في المال بقوله تعالى: ﴿وَإِنَّ كَثِيرًا مِنَ الْخُلَطَاءِ لَيَبْغِي بَعْضُهُمْ عَلَىٰ بَعْضٍ إِلَّا الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ﴾ (ص: 24)، ففي الآية إقرار لوجود "الخلطاء" أي الشركاء مع تحذير من ظلم بعضهم بعضاً. وقد عمل النبي ﷺ نفسه مضارباً بمال خديجة رضي الله عنها في تجارتها إلى الشام قبل البعثة، وهو أصل تاريخي معتبر لمشروعية المضاربة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'باب الشركات من «الفقه الإسلامي وأدلته» — د. وهبة الزحيلي', 1);
  END IF;

  -- 18) المساقاة والمزارعة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='4e2d531e-e022-4475-b379-b0ff7e6f2ead' AND title='المساقاة والمزارعة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('المساقاة والمزارعة', 'تعريف عقدي المشاركة الزراعية على سقي الشجر أو زراعة الأرض بجزء من الثمر أو الزرع', '4e2d531e-e022-4475-b379-b0ff7e6f2ead', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'المساقاة عقد بين صاحب شجر وعامل على أن يقوم العامل بسقيه ورعايته حتى يثمر، مقابل جزء معلوم شائع من ثمره. والمزارعة عقد بين صاحب أرض وعامل على أن يزرعها العامل بنفسه أو ببذره، مقابل جزء معلوم شائع مما تنتجه من الزرع. وكلاهما من عقود المشاركة التي تجمع بين مالك الأصل (الشجر أو الأرض) والعامل عليه.', 1),
    (v_lesson, 'evidence', 'دليلهما من السنة', 'ثبتت مشروعيتهما بحديث ابن عمر رضي الله عنهما المتفق عليه: «أن رسول الله ﷺ عامل أهل خيبر بشطر ما يخرج منها من ثمر أو زرع»، فكانت هذه المعاملة النبوية مع يهود خيبر أصلاً معتمداً عند جمهور الفقهاء لجواز المساقاة والمزارعة بجزء شائع من الناتج.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'كتابا المساقاة والمزارعة من «المغني» — ابن قدامة المقدسي', 1);
  END IF;

  -- 19) الإجارة والجعالة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='31689a6d-3212-440f-94b0-f7a24a80b900' AND title='الإجارة والجعالة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الإجارة والجعالة', 'تعريف عقد الإجارة على المنافع والأعمال، وعقد الجعالة على العمل غير المعلوم مسبقاً', '31689a6d-3212-440f-94b0-f7a24a80b900', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما', 'الإجارة عقد على منفعة معلومة (كسكنى دار) أو عمل معلوم (كخياطة ثوب) بعوض معلوم لمدة معينة، وهي من أكثر العقود شيوعاً في حياة الناس. والجعالة التزام عوض معلوم على عمل معين غير محدد المدة ولا معلوم مقداره مسبقاً، كجعل مكافأة لمن يجد شيئاً ضائعاً، وتفترق عن الإجارة بأن العامل فيها غير معيَّن ولا ملزَم بإتمام العمل قبل الشروع فيه.', 1),
    (v_lesson, 'evidence', 'أدلتهما من القرآن', 'من أدلة مشروعية الإجارة قصة موسى عليه السلام مع صاحب مدين، إذ قالت ابنته: ﴿يَا أَبَتِ اسْتَأْجِرْهُ إِنَّ خَيْرَ مَنِ اسْتَأْجَرْتَ الْقَوِيُّ الْأَمِينُ﴾ (القصص: 26)، ثم عقدا إجارة محددة المدة بقوله: ﴿عَلَىٰ أَنْ تَأْجُرَنِي ثَمَانِيَ حِجَجٍ﴾ (القصص: 27). ومن أدلة مشروعية الجعالة قصة يوسف عليه السلام، إذ قال منادي الملك: ﴿وَلِمَنْ جَاءَ بِهِ حِمْلُ بَعِيرٍ وَأَنَا بِهِ زَعِيمٌ﴾ (يوسف: 72)، وهو جُعل معلوم لمن يجد الصواع المفقود.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'بابا الإجارة والجعالة من «الملخص الفقهي» — الشيخ صالح بن فوزان الفوزان', 1);
  END IF;

  -- 20) السلم والرهن والقرض
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a7fcc428-f401-4094-8ab9-cd742d14cc94' AND title='السلم والرهن والقرض') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('السلم والرهن والقرض', 'تعريف بيع السلم وعقد الرهن توثيقاً للدَّين، والقرض الحسن بين الناس', 'a7fcc428-f401-4094-8ab9-cd742d14cc94', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها', 'السلم بيع موصوف في الذمة بثمن معجَّل يُدفع حالاً على أن يُسلَّم المبيع في أجل معلوم، ويشترط فيه معرفة الجنس والقدر والصفة والأجل. والرهن توثيق دَين بعين مالية، فإن لم يوفِّ المدين دَينه استوفاه الدائن من ثمنها. والقرض تمليك مال لآخر على أن يرد مثله عند القدرة من غير زيادة، وهو من أبواب الإحسان والتعاون بين الناس.', 1),
    (v_lesson, 'evidence', 'أدلتها', 'ثبتت مشروعية السلم بحديث ابن عباس رضي الله عنهما المتفق عليه: «من أسلف في شيء ففي كيل معلوم ووزن معلوم إلى أجل معلوم». ودلَّ على مشروعية الرهن قوله تعالى: ﴿وَإِنْ كُنْتُمْ عَلَىٰ سَفَرٍ وَلَمْ تَجِدُوا كَاتِبًا فَرِهَانٌ مَقْبُوضَةٌ﴾ (البقرة: 283). ورغَّب الله في القرض الحسن بقوله: ﴿مَنْ ذَا الَّذِي يُقْرِضُ اللَّهَ قَرْضًا حَسَنًا فَيُضَاعِفَهُ لَهُ أَضْعَافًا كَثِيرَةً﴾ (البقرة: 245).', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أبواب السلم والرهن والقرض من «الفقه الإسلامي وأدلته» — د. وهبة الزحيلي', 1);
  END IF;

  -- 21) العقود الحديثة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='3c3503d4-b900-4faa-bc4a-2c22af79c1d8' AND title='العقود المستحدثة وضابط الحكم عليها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('العقود المستحدثة وضابط الحكم عليها', 'القاعدة الفقهية العامة في التعامل مع العقود المالية المستجدة التي لم تُذكر باسمها عند المتقدمين', '3c3503d4-b900-4faa-bc4a-2c22af79c1d8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الضابط الفقهي العام', 'استحدث الناس في العصر الحديث عقوداً مالية لم تكن معروفة باسمها عند فقهاء المذاهب المتقدمين، كعقد الاستصناع بصورته المصرفية، والإجارة المنتهية بالتمليك، وبطاقات الائتمان، والتمويل الجماعي. والقاعدة الفقهية المعتبرة عند تكييف هذه العقود المستحدثة هي النظر إلى حقيقتها ومضمونها لا إلى اسمها الحادث، فإن كانت خالية من الربا والغرر الفاحش والجهالة المفضية للنزاع، وقائمة على تراضٍ حقيقي، فالأصل فيها الإباحة، وإلا كيَّفها الفقهاء بأقرب العقود المعروفة إليها لإلحاقها بحكمها.', 1),
    (v_lesson, 'evidence', 'أصل الإباحة في المعاملات', 'الأصل الذي يُبنى عليه هذا الضابط قوله تعالى: ﴿هُوَ الَّذِي خَلَقَ لَكُمْ مَا فِي الْأَرْضِ جَمِيعًا﴾ (البقرة: 29)، فقد امتنَّ الله على عباده بإباحة الانتفاع بما في الأرض أصلاً، ومن هذا الأصل استنبط الفقهاء القاعدة الكلية المشهورة: «الأصل في المعاملات الإباحة إلا بدليل يدل على التحريم»، خلافاً للعبادات التي أصلها التوقيف.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', '«المعاملات المالية المعاصرة» — د. محمد عثمان شبير (باب العقود المستحدثة)', 1);
  END IF;

  -- نشر التصنيفات الـ21 بعد اكتمال محتواها الأساسي
  UPDATE categories SET status='published', updated_at=now()
  WHERE slug IN (
    'buyu','riba','uqud-tawthiq','waqf-hiba-wasiyya','muamalat-bankiyya',
    'ashum-sukuk','umlat-raqmiyya','tamin','tijara-iliktroniyya','huquq-fikriyya',
    'wikala','hajr','daman-kafala-hawala','sulh-shufaa','ghasb-luqata',
    'wadia-ariya','sharika-mudaraba','musaqat-muzaraa','ijara-juala',
    'salam-rahn-qard','uqud-haditha'
  ) AND status='draft';
END $$;
